// Importa imagens que serão usadas na página
import imgP2 from "./img/dog5.png";
import imgP3 from "./img/dog2.jpg";
import imgP4 from "./img/dog3.jpg";
import imgP5 from "./img/dog1.jpg"



// Importa o arquivo de estilos CSS da página
import "./Style.css"; 

// ================== Componente Principal ==================
// Define o componente funcional "Home", que representa a página inicial
function Home() {
  return (
    // Container principal da página (usa a classe .home-container do CSS)
    <div className="home-container">
      
      {/* ================= Hero Section ================= */}
      {/* Seção de destaque inicial com título e slogan */}
      <section className="hero-section">
        <h1>Patas do Amanhã</h1>
        <p>Transformando a vida de animais com amor e cuidado.</p>
      </section>

      {/* Imagem PNG (dog5.png), estilizada pela classe .pts-imgpng */}
      <img className="pts-imgpng" src={imgP2} alt="Animal 1" />

      {/* ================= Sobre a ONG ================= */}
      {/* Texto explicativo sobre a história e origem da ONG */}
      <section className="about-section">
        <h2>Sobre a ONG</h2>
        <p>
          A "Patas do Amanhã" nasceu do desejo de transformar a vida de animais em situação de rua,
          oferecendo a eles uma nova oportunidade de encontrar amor e segurança. Fundada em 2020 por
          um grupo de voluntários apaixonados por animais, a ONG começou com pequenas ações de resgate
          e acolhimento na cidade de São Paulo.
        </p>
        <p>
          O projeto ganhou força após um evento marcante: durante uma tempestade em fevereiro de 2024,
          a equipe encontrou Bella, uma cadela Labrador assustada e desamparada. Seu resgate mobilizou
          toda a comunidade e reforçou a importância da missão da ONG. Desde então, a "Patas do Amanhã"
          expandiu suas operações, criando um sistema estruturado de resgates, adoção e castração acessível,
          sempre priorizando o bem-estar animal.
        </p>
        
        
        
      </section>

      {/* ================= Missão, Visão e Valores ================= */}
      {/* Sessão com três cards explicativos */}
      <section className="mission-vision-values">

        {/* Card Missão */}
        <div className="card">
          <h2>Missão</h2>
          <p>
            <img className="pts-img3" src={imgP3 } alt="" />
            Resgatar, reabilitar e encontrar lares amorosos para animais em situação de vulnerabilidade.
            Atuamos promovendo o respeito, a conscientização e o bem-estar animal, garantindo que cada resgatado
            tenha uma segunda chance de viver com dignidade e carinho.
          </p>
        </div>

        {/* Card Visão */}
        <div className="card">
          <h2>Visão</h2>
          <p>
             <img className="pts-img2" src={imgP5 } alt="" />
            Sonhamos com um mundo onde nenhum animal seja abandonado ou sofra maus-tratos. Trabalhamos para
            construir uma sociedade mais consciente e responsável, onde cada animal tenha a oportunidade
            de viver seguro, saudável e cercado de amor.
          </p>
        </div>

        {/* Card Valores */}
        <div className="card">
          <h2>Valores</h2>
          <ul>
             <img className="pts-img4" src={imgP4 } alt="" />
            <li>Bem-Estar Animal: Compromisso com o cuidado e a dignidade dos animais resgatados.</li>
            <li>Empatia e Amor: Acreditamos no poder do amor e da empatia para transformar vidas.</li>
            <li>Responsabilidade Social: Conscientizamos e educamos a sociedade sobre a importância da adoção e da castração.</li>
          </ul>
        </div>
      </section>
    
    </div>
  );
}

// Exporta o componente para que ele possa ser usado em outras partes do app
export default Home;
